/**
 * frontend/src/components/IntakeFlow.jsx
 *
 * Screen 2 — Intake conversation (Claude conductor).
 *
 * Figma frame: 02-Intake-Conversation
 */

import React, { useCallback, useEffect, useRef, useState } from "react";

const API_BASE = process.env.REACT_APP_API_URL || "http://localhost:8000";

function stripIntakeUiBlock(text) {
  if (!text) return "";
  const fence = "```intake-ui";
  const i = text.indexOf(fence);
  if (i === -1) return text;
  const start = i + fence.length;
  const end = text.indexOf("```", start);
  if (end === -1) return text.slice(0, i).trimEnd();
  const before = text.slice(0, i).trimEnd();
  const after = text.slice(end + 3).trimStart();
  if (before && after) return `${before}\n\n${after}`.trim();
  return (before || after).trim();
}

/** Keep only 2–4 options for chip UI; otherwise return []. */
function normalizeSuggestedOptions(raw) {
  if (!Array.isArray(raw)) return [];
  const out = raw.map((x) => String(x).trim()).filter(Boolean).slice(0, 4);
  return out.length >= 2 ? out : [];
}

function displayAssistantText(raw) {
  let t = stripIntakeUiBlock(raw || "");
  const fence = "```json";
  const i = t.indexOf(fence);
  if (i === -1) return t;
  return t.slice(0, i).trimEnd();
}

/**
 * @param {Object} props
 * @param {string | null} [props.initialUserMessage] — from landing; sent as first user message after start
 * @param {Object | null} [props.selectedUseCase] — optional `first_question` after opening
 * @param {function} props.onComplete - `(session_config) => void` after user approves optimized prompt
 * @param {function} [props.onBack] - optional return to landing
 */
function IntakeFlow({ initialUserMessage, selectedUseCase, onComplete, onBack }) {
  const [sessionId, setSessionId] = useState(null);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [bootError, setBootError] = useState(null);
  const [sendError, setSendError] = useState(null);
  const [starting, setStarting] = useState(true);
  const [sending, setSending] = useState(false);
  const [intakeComplete, setIntakeComplete] = useState(false);
  const [pendingConfig, setPendingConfig] = useState(null);
  const [editedPrompt, setEditedPrompt] = useState("");
  const [promptEditMode, setPromptEditMode] = useState(false);
  const listEndRef = useRef(null);
  const promptTextareaRef = useRef(null);
  const autoSeedSentForSessionRef = useRef(null);

  useEffect(() => {
    listEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, intakeComplete]);

  useEffect(() => {
    if (promptEditMode) promptTextareaRef.current?.focus();
  }, [promptEditMode]);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      setStarting(true);
      setBootError(null);
      setMessages([]);
      setSessionId(null);
      setIntakeComplete(false);
      setPendingConfig(null);
      setEditedPrompt("");
      setPromptEditMode(false);
      try {
        const res = await fetch(`${API_BASE}/api/intake/start`, { method: "POST" });
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        const data = await res.json();
        if (cancelled) return;
        setSessionId(data.session_id);
        const next = [{ role: "assistant", content: data.message || "" }];
        const fq = selectedUseCase?.first_question;
        if (fq) {
          next.push({
            role: "assistant",
            content: fq,
            variant: "use_case",
          });
        }
        setMessages(next);
      } catch (e) {
        if (!cancelled) setBootError(e.message || "Could not start intake");
      } finally {
        if (!cancelled) setStarting(false);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [selectedUseCase]);

  const submitIntakeText = useCallback(
    async (rawText, { restoreInputOnFailure } = { restoreInputOnFailure: false }) => {
      const text = rawText.trim();
      if (!text || !sessionId || sending || intakeComplete) return;
      setSendError(null);
      setSending(true);
      setMessages((m) => [...m, { role: "user", content: text }]);
      try {
        const res = await fetch(`${API_BASE}/api/intake/respond`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ session_id: sessionId, message: text }),
        });
        if (!res.ok) {
          if (res.status === 404) throw new Error("Intake session expired. Go back and try again.");
          const errBody = await res.json().catch(() => ({}));
          throw new Error(errBody.detail || `HTTP ${res.status}`);
        }
        const data = await res.json();
        const opts = normalizeSuggestedOptions(data.suggested_options);
        setMessages((m) => [
          ...m,
          {
            role: "assistant",
            content: data.message || "",
            ...(opts.length >= 2 ? { suggestedOptions: opts } : {}),
          },
        ]);
        if (data.status === "complete") {
          setIntakeComplete(true);
          setPendingConfig(data.config || {});
          const op = data.config?.optimized_prompt || "";
          setEditedPrompt(typeof op === "string" ? op : "");
          setPromptEditMode(false);
        }
      } catch (e) {
        setSendError(e.message || "Send failed");
        setMessages((m) => {
          const copy = [...m];
          const last = copy[copy.length - 1];
          if (last?.role === "user" && last.content === text) copy.pop();
          return copy;
        });
        if (restoreInputOnFailure) setInput(text);
      } finally {
        setSending(false);
      }
    },
    [sessionId, sending, intakeComplete]
  );

  const sendMessage = useCallback(async () => {
    const text = input.trim();
    if (!text) return;
    setInput("");
    await submitIntakeText(text, { restoreInputOnFailure: true });
  }, [input, submitIntakeText]);

  useEffect(() => {
    if (!sessionId || starting || intakeComplete) return;
    const seed = initialUserMessage?.trim();
    if (!seed) return;
    if (autoSeedSentForSessionRef.current === sessionId) return;
    autoSeedSentForSessionRef.current = sessionId;
    submitIntakeText(seed, { restoreInputOnFailure: false });
  }, [sessionId, starting, intakeComplete, initialUserMessage, submitIntakeText]);

  const handleApprove = useCallback(() => {
    if (!pendingConfig || typeof onComplete !== "function") return;
    const prompt = editedPrompt.trim();
    onComplete({
      ...pendingConfig,
      optimized_prompt: prompt || pendingConfig.optimized_prompt,
    });
  }, [pendingConfig, editedPrompt, onComplete]);

  const lastMessage = messages.length ? messages[messages.length - 1] : null;
  const awaitingReplyToAssistant =
    lastMessage?.role === "assistant" && !sending && !intakeComplete && !starting;
  const optionChips = awaitingReplyToAssistant
    ? normalizeSuggestedOptions(lastMessage.suggestedOptions)
    : [];
  const showOptionChips = optionChips.length >= 2;

  return (
    <div className="flex min-h-screen flex-col bg-[#0d0d0d] text-[#e8e8e8]">
      <div className="shrink-0 px-4 pt-4 sm:px-6">
        <div className="mx-auto max-w-3xl">
          {typeof onBack === "function" && (
            <button
              type="button"
              onClick={onBack}
              className="text-sm text-[#888888] transition-colors hover:text-[#e8e8e8]"
            >
              ← Home
            </button>
          )}
        </div>
      </div>

      <div className="mx-auto flex w-full max-w-3xl flex-1 flex-col overflow-hidden px-4 pb-6 pt-3 sm:px-6">
        {bootError && (
          <p className="mb-3 text-sm text-red-400" role="alert">
            {bootError}
          </p>
        )}
        {sendError && (
          <p className="mb-3 text-sm text-red-400" role="alert">
            {sendError}
          </p>
        )}

        <div className="min-h-0 flex-1 space-y-4 overflow-y-auto pb-4">
          {starting && <p className="text-sm text-text-secondary">Starting conversation…</p>}

          {messages.map((msg, i) => {
            const isUser = msg.role === "user";
            const bubble = isUser ? (
              <div
                key={i}
                className="ml-auto max-w-[min(100%,36rem)] rounded-lg bg-[#2a2a2a] px-4 py-3 text-[0.9375rem] leading-relaxed text-[#e8e8e8]"
              >
                {msg.content}
              </div>
            ) : (
              <div key={i} className="mr-auto w-full max-w-[min(100%,36rem)]">
                <div className="mb-2 flex items-center gap-2">
                  <span className="h-2 w-2 shrink-0 rounded-full bg-claude" aria-hidden />
                  <span className="text-sm font-medium text-[#e8e8e8]">Claude</span>
                </div>
                <div className="rounded-lg border border-[#2a2a2a] bg-[#1e1e1e] px-4 py-3 text-[0.9375rem] leading-relaxed text-[#e8e8e8]">
                  {msg.variant === "use_case" && (
                    <p className="mb-2 text-xs font-semibold uppercase tracking-wide text-[#888888]">
                      For this use case
                    </p>
                  )}
                  <div className="whitespace-pre-wrap">
                    {msg.role === "assistant"
                      ? displayAssistantText(msg.content)
                      : msg.content}
                  </div>
                </div>
              </div>
            );
            return bubble;
          })}
          <div ref={listEndRef} />
        </div>

        {!intakeComplete && !starting && sessionId && (
          <div className="shrink-0 space-y-3 border-t border-border pt-4">
            {showOptionChips && (
              <div>
                <p className="mb-2 text-xs font-semibold uppercase tracking-wide text-text-secondary">
                  Choose a reply
                </p>
                <div className="grid grid-cols-1 gap-2 sm:grid-cols-2">
                  {optionChips.map((label, idx) => (
                    <button
                      key={`${idx}-${label.slice(0, 24)}`}
                      type="button"
                      disabled={sending}
                      onClick={() => submitIntakeText(label, { restoreInputOnFailure: false })}
                      className="rounded-lg border border-border border-l-4 border-l-claude bg-surface px-3 py-2.5 text-left text-sm leading-snug text-text-primary transition-colors hover:border-border-focus disabled:cursor-not-allowed disabled:opacity-50"
                    >
                      {label}
                    </button>
                  ))}
                </div>
              </div>
            )}
            <form
              onSubmit={(e) => {
                e.preventDefault();
                sendMessage();
              }}
            >
              <label htmlFor="intake-reply" className="sr-only">
                Your message
              </label>
              <textarea
                id="intake-reply"
                rows={showOptionChips ? 2 : 3}
                value={input}
                onChange={(e) => setInput(e.target.value)}
                disabled={sending}
                placeholder={
                  showOptionChips ? "Or type your own answer…" : "Reply to Claude…"
                }
                className="w-full resize-y rounded-lg border border-border bg-surface px-3 py-2 text-sm text-text-primary caret-chrome placeholder:text-text-secondary focus:border-border-focus focus:outline-none disabled:opacity-60"
              />
              <div className="mt-2 flex justify-end">
                <button
                  type="submit"
                  disabled={sending || !input.trim()}
                  className="rounded-lg border border-border bg-surface px-4 py-2 text-sm font-medium text-text-primary hover:border-accent-ui focus:border-border-focus focus:outline-none disabled:cursor-not-allowed disabled:opacity-40"
                >
                  {sending ? "Sending…" : "Send"}
                </button>
              </div>
            </form>
          </div>
        )}

        {intakeComplete && (
          <div className="shrink-0 space-y-3 border-t border-border pt-4">
            <h2 className="text-base font-semibold text-text-primary">Optimized prompt</h2>
            <p className="text-sm text-text-secondary">
              Review the prompt. Use Edit to change it, then Approve to continue to the roundtable.
            </p>
            {promptEditMode ? (
              <textarea
                ref={promptTextareaRef}
                rows={10}
                value={editedPrompt}
                onChange={(e) => setEditedPrompt(e.target.value)}
                className="w-full resize-y rounded-lg border border-border bg-surface px-3 py-2 text-sm leading-relaxed text-text-primary caret-chrome focus:border-border-focus focus:outline-none"
              />
            ) : (
              <div className="max-h-64 overflow-y-auto rounded-lg border border-border bg-surface px-3 py-3 text-sm leading-relaxed text-text-primary whitespace-pre-wrap">
                {editedPrompt || (
                  <span className="text-text-secondary">(No optimized_prompt in config)</span>
                )}
              </div>
            )}
            <div className="flex flex-wrap gap-2">
              {!promptEditMode ? (
                <button
                  type="button"
                  onClick={() => setPromptEditMode(true)}
                  className="rounded-lg border border-border px-4 py-2 text-sm font-medium text-text-primary hover:border-accent-ui focus:border-border-focus focus:outline-none"
                >
                  Edit
                </button>
              ) : (
                <button
                  type="button"
                  onClick={() => {
                    setEditedPrompt(pendingConfig?.optimized_prompt || "");
                    setPromptEditMode(false);
                  }}
                  className="rounded-lg border border-border px-4 py-2 text-sm font-medium text-text-primary hover:border-accent-ui focus:border-border-focus focus:outline-none"
                >
                  Cancel edit
                </button>
              )}
              <button
                type="button"
                onClick={handleApprove}
                className="rounded-lg border border-border bg-surface px-4 py-2 text-sm font-medium text-text-primary hover:border-accent-ui focus:border-border-focus focus:outline-none"
              >
                Approve
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default IntakeFlow;
